import { useQuery } from '@tanstack/react-query';
import React, { useEffect } from 'react'
import { useNavigate, useParams } from 'react-router-dom'
import { Img_URL, fetchSearch } from '../../utils/fetchApi';
import '../SearchItem/search.scss';

const Search = () => {
  const {searchTerm} = useParams();
  const navigate= useNavigate();

    const {isLoading,isError,error,data:searchItem,refetch}=useQuery({
      queryKey:['searchItem'],
      queryFn: ()=> fetchSearch(`${searchTerm}`)
      .then((res)=>{
        console.log(res);
        return res.results;
      }
        ),
    })

    useEffect(()=>{
      refetch();
    })

  if (isLoading) {
    return (
      <div className="loading">
        <h1>Loading</h1>
      </div>
    );
  } else if (isError) {
    return (
      <div className="error">
        <p>{searchTerm}Not Found...</p>
      </div>
    );
  }else{
  return (
    <section className='search'>

      {
        searchItem ? <h2>{searchTerm} Not Found...</h2> :
        searchItem.map((item)=>(
         <div key={item.id} onClick={()=> navigate(`/movie/${item.id}`)}>
          <h1>{item.title}</h1>
          <aside>
          { 
            item.poster_path && <img src={ `${Img_URL}${item.poster_path}`} alt="" />
          }
          <p>{item.overview}</p>
          </aside>
        </div>
        ))
      }
    </section>
  )
    }
  }
export default Search
